const agents = $input.all().map(item => item.json);
const today = new Date();
const day = today.getDay();
if (day === 0) today.setDate(today.getDate() - 2);
else if (day === 6) today.setDate(today.getDate() - 1);
const scrapeDate = today.toISOString().slice(0, 10);

return [{
  json: {
    scrape_date: scrapeDate,
    agents: agents
  }
}];

// Build Slack summary split by site (ATX=AUS, CLT=CHA)
const payload = $node['Build Ingestion Payload'].json;
const agents = payload.agents || [];
const scrapeDate = payload.scrape_date;

// Fetch agent roster for site mapping
const rosterResp = await fetch(
  'https://bcibmmbxrjfiulofserv.supabase.co/rest/v1/agents?select=name,site&is_active=eq.true',
  { headers: { 'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImJjaWJtbWJ4cmpmaXVsb2ZzZXJ2Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQxMTMzNzAsImV4cCI6MjA4OTY4OTM3MH0.IIuxX_m34M4QOPORUr7v04AO3aLgdQnvMhD8rOjVnhQ' }}
);
const roster = await rosterResp.json();
const siteMap = {};
for (const r of roster) siteMap[r.name] = r.site === 'AUS' ? 'ATX' : 'CLT';

const sites = {
  ATX: { sales: 0, premium: 0, agents: 0 },
  CLT: { sales: 0, premium: 0, agents: 0 }
};

for (const a of agents) {
  const site = siteMap[a.agent_name] || 'CLT';
  const s = sites[site];
  const sales = (a.ib_sales||0) + (a.ob_sales||0) + (a.custom_sales||0);
  const premium = (a.ib_premium||0) + (a.ob_premium||0) + (a.custom_premium||0);
  s.sales += sales;
  s.premium += premium;
  s.agents++;
}

const totalSales = sites.ATX.sales + sites.CLT.sales;
const totalPremium = sites.ATX.premium + sites.CLT.premium;
const atxCR = sites.ATX.agents > 0 ? ((sites.ATX.sales / sites.ATX.agents) * 100).toFixed(1) : '0';
const cltCR = sites.CLT.agents > 0 ? ((sites.CLT.sales / sites.CLT.agents) * 100).toFixed(1) : '0';
const time = new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Chicago' });
const fmt = (n) => '$' + Math.round(n).toLocaleString();

const message = {
  text: `DSB Scrape — ${scrapeDate} @ ${time} CST`,
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: `DSB Production Update — ${scrapeDate}`, emoji: true } },
    { type: 'section', text: { type: 'mrkdwn', text: `*${agents.length} agents* scraped at *${time} CST*` } },
    { type: 'divider' },
    { type: 'section', fields: [
      { type: 'mrkdwn', text: `*ATX (Austin)*\n:chart_with_upwards_trend: *${sites.ATX.sales}* sales\n:moneybag: *${fmt(sites.ATX.premium)}* premium\n:busts_in_silhouette: ${sites.ATX.agents} agents` },
      { type: 'mrkdwn', text: `*CLT (Charlotte)*\n:chart_with_upwards_trend: *${sites.CLT.sales}* sales\n:moneybag: *${fmt(sites.CLT.premium)}* premium\n:busts_in_silhouette: ${sites.CLT.agents} agents` }
    ]},
    { type: 'divider' },
    { type: 'section', text: { type: 'mrkdwn', text: `*Combined:* *${totalSales}* sales | *${fmt(totalPremium)}* premium` } },
    { type: 'context', elements: [{ type: 'mrkdwn', text: `Scrape date: ${scrapeDate} | Next scrape in ~2 hours` }] }
  ]
};

return [{ json: message }];
